import{c as t,Q as r,j as a,m as s}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Is Grep All You Need? How Agent Harnesses Reshape Agentic Search","description":"","frontmatter":{"title":"Is Grep All You Need? How Agent Harnesses Reshape Agentic Search","arxiv_id":2605.15184,"authors":"Sahil Sen, Akhil Kasturi, Elias Lumer, Anmol Gulati, Vamse Kumar Subbiah","fetched":"2026-05-26T00:00:00.000Z","published":"2026-05-14T00:00:00.000Z","source":"https://arxiv.org/abs/2605.15184","source_tier":"P"},"headers":[],"relativePath":"research/papers/2026-05-14-is-grep-all-you-need-agentic-search-2605-15184.md","filePath":"research/papers/2026-05-14-is-grep-all-you-need-agentic-search-2605-15184.md","lastUpdated":1779901665000}'),n={name:"research/papers/2026-05-14-is-grep-all-you-need-agentic-search-2605-15184.md"};function o(i,e,d,l,c,h){return r(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="is-grep-all-you-need-how-agent-harnesses-reshape-agentic-search" tabindex="-1">Is Grep All You Need? How Agent Harnesses Reshape Agentic Search <a class="header-anchor" href="#is-grep-all-you-need-how-agent-harnesses-reshape-agentic-search" aria-label="Permalink to &quot;Is Grep All You Need? How Agent Harnesses Reshape Agentic Search&quot;">​</a></h1><p><strong>Authors</strong>: Sahil Sen, Akhil Kasturi, Elias Lumer, Anmol Gulati, Vamse Kumar Subbiah (PricewaterhouseCoopers, U.S.) <strong>Published</strong>: May 14, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.15184" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.15184</a><strong>arXiv ID</strong>: 2605.15184 <strong>License</strong>: CC BY 4.0 <strong>Categories</strong>: cs.CL</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Recent advances in Large Language Model (LLM) agents have enabled complex agentic workflows where models autonomously retrieve information, call tools, and reason over large corpora to complete tasks on behalf of users. Despite the growing adoption of retrieval-augmented generation (RAG) in agentic systems, existing literature lacks a systematic comparison of how retrieval strategy choice interacts with agent architecture and tool-calling paradigm. Important practical dimensions, including how tool outputs are presented to the model and how performance changes when searches must cope with more irrelevant surrounding text, remain under-explored in agent loops.</p><p>This paper reports an empirical study organized into two experiments. Experiment 1 compares grep and vector retrieval on a 116-question sample from LongMemEval, using a custom agent harness (Chronos) and provider-native CLI harnesses (Claude Code, Codex, and Gemini CLI), for both inline tool results and file-based tool results that the model reads separately. Experiment 2 compares grep-only and vector-only retrieval while progressively mixing in additional unrelated conversation history, so that each query is embedded in more distracting material alongside the passages that matter. Across Chronos and the provider CLIs, grep generally yields higher accuracy than vector retrieval in our comparisons in experiment 1; at the same time, overall scores still depend strongly on which harness and tool-calling style is used, even when the underlying conversation data are the same.</p><p><strong>Keywords</strong>: Agentic Search, Semantic Search, Lexical Search, Context Engineering, Agent Harnesses, LLM Evaluation, Grep</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>Retrieval strategy, agent harness, and delivery mechanism function as a <strong>single jointly-evaluated system</strong>, not independent design choices. The same LLM backbone under different harnesses shows accuracy swings comparable to switching retrieval strategies entirely. Inline grep consistently beats inline vector across all tested harness–model pairs on LongMemEval; however, file-based delivery can invert this ordering.</p><hr><h2 id="_1-introduction" tabindex="-1">1. Introduction <a class="header-anchor" href="#_1-introduction" aria-label="Permalink to &quot;1. Introduction&quot;">​</a></h2><p>Modern LLM agents increasingly rely on RAG to access external knowledge at inference time, enabling them to reason over corpora that far exceed their context windows. Through tool calling, agents issue search queries, receive ranked results, and iteratively refine their understanding before producing an answer. Two retrieval paradigms dominate:</p><ul><li><strong>Semantic vector search</strong>: embeds queries and documents into a shared latent space for approximate nearest-neighbor matching</li><li><strong>Lexical search</strong> (grep, BM25, regex): performs exact or pattern-based matching over raw text</li></ul><p>While vector search has become the default in most RAG systems, lexical search remains widely used due to simplicity, stability, and low embedding cost. However, how retrieval strategy interacts with agent architecture and tool-calling paradigm in end-to-end agentic workflows remains poorly understood.</p><p>The emergence of provider-native CLI agents (Claude Code, Codex, Gemini CLI) has created a new class of agentic systems that differ fundamentally from custom-built harnesses. These provider harnesses embed tool calling into a shell-based interface where the model has direct access to command-line tools including grep, while custom harnesses offer fine-grained control over the tool-calling loop, context construction, and result formatting.</p><p><strong>Paper contributions:</strong></p><ol><li><strong>Retrieval, harness, and presentation</strong>: Evidence on how lexical vs. dense retrieval combines with agent orchestration and inline vs. file-based output delivery.</li><li><strong>Noise and scale</strong>: Characterization of how end-to-end behavior evolves as irrelevant surrounding content grows relative to task-relevant material.</li><li><strong>Heterogeneity across agent stacks</strong>: Direct comparison showing retrieval effectiveness is not stable across architecturally distinct harnesses even when the underlying text corpus is held fixed.</li></ol><hr><h2 id="_2-overview-of-retrieval-in-agentic-systems" tabindex="-1">2. Overview of Retrieval in Agentic Systems <a class="header-anchor" href="#_2-overview-of-retrieval-in-agentic-systems" aria-label="Permalink to &quot;2. Overview of Retrieval in Agentic Systems&quot;">​</a></h2><p>Retrieval in agentic systems is iterative and agent-directed: the model decides what to search for, how many queries to issue, and whether retrieved results are sufficient. This process is mediated by two design dimensions: the <strong>retrieval strategy</strong> and the <strong>agent harness</strong>.</p><h3 id="_2-1-retrieval-strategies" tabindex="-1">2.1. Retrieval Strategies <a class="header-anchor" href="#_2-1-retrieval-strategies" aria-label="Permalink to &quot;2.1. Retrieval Strategies&quot;">​</a></h3><h4 id="_2-1-1-lexical-search" tabindex="-1">2.1.1. Lexical Search <a class="header-anchor" href="#_2-1-1-lexical-search" aria-label="Permalink to &quot;2.1.1. Lexical Search&quot;">​</a></h4><p>Performs exact or pattern-based matching over raw text. Classical approaches like BM25 score by term frequency and inverse document frequency; grep uses regular expressions or substring matching. Requirements: no embedding model or vector index — negligible computational cost beyond the text scan. The BEIR benchmark showed BM25 remains competitive across diverse retrieval tasks, often outperforming early dense retrieval models in zero-shot settings.</p><p>Learned sparse representations (SPLADE) extend lexical matching by expanding query and document terms through a learned vocabulary, bridging the gap between exact matching and semantic understanding while preserving interpretability and efficiency.</p><h4 id="_2-1-2-semantic-search" tabindex="-1">2.1.2. Semantic Search <a class="header-anchor" href="#_2-1-2-semantic-search" aria-label="Permalink to &quot;2.1.2. Semantic Search&quot;">​</a></h4><p>Encodes queries and documents as dense vectors; retrieves via approximate nearest-neighbor search. RAG systems couple dense retrieval with a generative model. Modern pipelines embed documents at indexing time and queries at inference time, with optional post-retrieval reranking. Semantic search handles paraphrases and semantic similarity but introduces dependencies on embedding model quality, vector index infrastructure, and indexing latency.</p><h4 id="_2-1-3-hybrid-approaches" tabindex="-1">2.1.3. Hybrid Approaches <a class="header-anchor" href="#_2-1-3-hybrid-approaches" aria-label="Permalink to &quot;2.1.3. Hybrid Approaches&quot;">​</a></h4><p>Combines lexical and semantic signals. Reciprocal Rank Fusion (RRF) merges ranked lists without score calibration. Late interaction models (ColBERT) compute fine-grained token-level similarity. Sparse and dense methods often retrieve different relevant documents, making their combination more effective than either alone. In agentic settings, hybrid retrieval can also emerge organically when agents have access to both tool types.</p><h3 id="_2-2-agent-harnesses" tabindex="-1">2.2. Agent Harnesses <a class="header-anchor" href="#_2-2-agent-harnesses" aria-label="Permalink to &quot;2.2. Agent Harnesses&quot;">​</a></h3><p>The agent harness manages the tool-calling loop: constructs the prompt, dispatches tool calls, receives results, and decides whether to continue or produce a final answer.</p><h4 id="_2-2-1-custom-harnesses" tabindex="-1">2.2.1. Custom Harnesses <a class="header-anchor" href="#_2-2-1-custom-harnesses" aria-label="Permalink to &quot;2.2.1. Custom Harnesses&quot;">​</a></h4><p>Built by developers using agent frameworks, provider SDKs, or custom code. Provide fine-grained control over every stage: system prompt, tool definitions, context construction, result formatting, and iteration termination criteria. The ReAct paradigm (reasoning traces interleaved with tool actions) is most widely adopted. Custom harnesses allow explicit context window management (summarizing or discarding earlier results). <strong>Tradeoff</strong>: significant developmental overhead.</p><h4 id="_2-2-2-provider-native-cli-harnesses" tabindex="-1">2.2.2. Provider-Native CLI Harnesses <a class="header-anchor" href="#_2-2-2-provider-native-cli-harnesses" aria-label="Permalink to &quot;2.2.2. Provider-Native CLI Harnesses&quot;">​</a></h4><p>Embed tool calling into a shell-based interface with direct model access to system utilities (grep, find, cat, etc.). The harness manages context construction and iteration control according to provider&#39;s internal implementation, which is largely opaque to users. <strong>Advantages</strong>: minimal setup cost, leverages provider&#39;s optimized context engineering. <strong>Sacrifice</strong>: fine-grained control. Notably, when grep is available as a native bash tool, the boundary between &quot;retrieval strategy&quot; and &quot;agent capability&quot; blurs — the agent can construct its own grep commands dynamically.</p><h3 id="_2-3-tool-calling-architectures" tabindex="-1">2.3. Tool-Calling Architectures <a class="header-anchor" href="#_2-3-tool-calling-architectures" aria-label="Permalink to &quot;2.3. Tool-Calling Architectures&quot;">​</a></h3><p>Tool-calling method is a <strong>context engineering decision</strong>.</p><h4 id="_2-3-1-standard-inline" tabindex="-1">2.3.1. Standard (Inline) <a class="header-anchor" href="#_2-3-1-standard-inline" aria-label="Permalink to &quot;2.3.1. Standard (Inline)&quot;">​</a></h4><p>Search results returned directly as tool response messages appended to the conversation context. Simple — results appear inline. However, large result sets compete for context window space with system prompt, conversation history, and previous tool results, creating <strong>context rot</strong> that can degrade performance on long-horizon tasks.</p><h4 id="_2-3-2-programmatic-file-based" tabindex="-1">2.3.2. Programmatic (File-Based) <a class="header-anchor" href="#_2-3-2-programmatic-file-based" aria-label="Permalink to &quot;2.3.2. Programmatic (File-Based)&quot;">​</a></h4><p>Results written to disk; model receives only a file path or summary pointer. Decouples retrieval result size from context window pressure. Enables <strong>progressive disclosure</strong> — agent reads only a subset based on metadata. <strong>Tradeoff</strong>: indirectness; agent must execute additional tool call to access results, adding latency and requiring understanding of the file-based workflow.</p><hr><h2 id="_3-methodology" tabindex="-1">3. Methodology <a class="header-anchor" href="#_3-methodology" aria-label="Permalink to &quot;3. Methodology&quot;">​</a></h2><h3 id="_3-1-task-and-dataset" tabindex="-1">3.1. Task and Dataset <a class="header-anchor" href="#_3-1-task-and-dataset" aria-label="Permalink to &quot;3.1. Task and Dataset&quot;">​</a></h3><p>Evaluates on a <strong>116-question representative subset of LongMemEval</strong> (Wu et al., 2025), which tests an agent&#39;s ability to answer questions over long conversations spanning multiple sessions. Each question has:</p><ul><li>One or more <strong>oracle sessions</strong> containing the information needed to answer correctly</li><li>Variable number of <strong>distractor sessions</strong> irrelevant to the query</li></ul><p><strong>Question categories</strong> (6):</p><ul><li><code>knowledge-update</code>: tracking state changes over time</li><li><code>multi-session</code>: aggregating information across sessions</li><li><code>single-session-assistant</code>: recalling model-generated content</li><li><code>single-session-preference</code>: user personal preferences</li><li><code>single-session-user</code>: user-stated facts</li><li><code>temporal-reasoning</code>: computing durations, ordering events, resolving dates</li></ul><h3 id="_3-2-retrieval-implementations" tabindex="-1">3.2. Retrieval Implementations <a class="header-anchor" href="#_3-2-retrieval-implementations" aria-label="Permalink to &quot;3.2. Retrieval Implementations&quot;">​</a></h3><h4 id="_3-2-1-structured-events-via-chronos" tabindex="-1">3.2.1. Structured Events via Chronos <a class="header-anchor" href="#_3-2-1-structured-events-via-chronos" aria-label="Permalink to &quot;3.2.1. Structured Events via Chronos&quot;">​</a></h4><p>The search layer operates over per-question files, serializing LongMemEval dialogue turns together with structured temporal events extracted via the Chronos preprocessing pipeline. Chronos targets long-horizon conversation memory by surfacing salient time structure (explicit dates, intervals, related time spans) as first-class text records coupled with raw utterances.</p><p>Two reasons for adopting this layer:</p><ol><li>Study evaluates search techniques, not temporal reasoning — structured event extraction ensures success on temporal items reflects evidence location ability, not date reconstruction from fragmented mentions.</li><li>Mirrors preprocessing a long-memory agent would use in deployment → realistic production configuration.</li></ol><h4 id="_3-2-2-lexical-search-grep" tabindex="-1">3.2.2. Lexical Search (Grep) <a class="header-anchor" href="#_3-2-2-lexical-search-grep" aria-label="Permalink to &quot;3.2.2. Lexical Search (Grep)&quot;">​</a></h4><p>Loads conversation turns and extracted temporal events from per-question files into memory; executes regex matching over raw text fields. Results scored by match count and returned. <strong>Requirements</strong>: no embedding model, vector index, or external service — all matching performed in-process over local files.</p><h4 id="_3-2-3-semantic-search-vector" tabindex="-1">3.2.3. Semantic Search (Vector) <a class="header-anchor" href="#_3-2-3-semantic-search-vector" aria-label="Permalink to &quot;3.2.3. Semantic Search (Vector)&quot;">​</a></h4><p>Queries a search index populated at ingestion time. Each turn and temporal event is embedded and stored in a per-question index with a versioned schema. At query time, embeds the natural language query and retrieves via approximate nearest-neighbor search. A reranking step re-scores passages before returning top-k results (k selected by the agent).</p><h3 id="_3-3-agent-harnesses" tabindex="-1">3.3. Agent Harnesses <a class="header-anchor" href="#_3-3-agent-harnesses" aria-label="Permalink to &quot;3.3. Agent Harnesses&quot;">​</a></h3><h4 id="_3-3-1-custom-harness-chronos" tabindex="-1">3.3.1. Custom Harness (Chronos) <a class="header-anchor" href="#_3-3-1-custom-harness-chronos" aria-label="Permalink to &quot;3.3.1. Custom Harness (Chronos)&quot;">​</a></h4><p>Implements an agent using LangChain with access to four search tools (grep and vector search over turns and events). Uses <strong>dynamic prompting</strong>: system instructions, search hints, and tool-use guidance depend on the detected question category (e.g., temporal reasoning vs. preference recall). The agent starts each episode with category-conditioned guidance, followed by an initial broad context block (top-15 vector results) before the tool-calling loop begins. Loop continues until the model produces a final answer.</p><h4 id="_3-3-2-provider-native-cli-harnesses" tabindex="-1">3.3.2. Provider-Native CLI Harnesses <a class="header-anchor" href="#_3-3-2-provider-native-cli-harnesses" aria-label="Permalink to &quot;3.3.2. Provider-Native CLI Harnesses&quot;">​</a></h4><p>Evaluates three provider-native CLI agents: <strong>Claude Code</strong>, <strong>Codex</strong>, and <strong>Gemini CLI</strong>. Each receives the question and a dynamically generated search strategy, and can invoke bash-callable wrapper scripts for grep and vector search via absolute paths. In standard mode, the process was spawned in a sandbox to ensure the model has access to only relevant files.</p><h3 id="_3-4-tool-calling-architectures" tabindex="-1">3.4. Tool-Calling Architectures <a class="header-anchor" href="#_3-4-tool-calling-architectures" aria-label="Permalink to &quot;3.4. Tool-Calling Architectures&quot;">​</a></h3><ul><li><strong>Standard (Inline)</strong>: Search scripts print results directly to stdout. For Chronos, results returned as tool response messages. For CLI harnesses, stdout appended to working context.</li><li><strong>Programmatic (File-Based)</strong>: All results written to a file the agent then reads or searches.</li></ul><h3 id="_3-5-models" tabindex="-1">3.5. Models <a class="header-anchor" href="#_3-5-models" aria-label="Permalink to &quot;3.5. Models&quot;">​</a></h3><p>Five LLMs evaluated across a range of capability levels:</p><ul><li><strong>Claude Opus 4.6</strong></li><li><strong>Claude Haiku 4.5</strong></li><li><strong>GPT-5.4</strong></li><li><strong>Gemini 3.1 Pro</strong></li><li><strong>Gemini 3.1 Flash-Lite</strong></li></ul><h3 id="_3-6-evaluation" tabindex="-1">3.6. Evaluation <a class="header-anchor" href="#_3-6-evaluation" aria-label="Permalink to &quot;3.6. Evaluation&quot;">​</a></h3><p>Follows LongMemEval evaluation protocol. Uses <strong>GPT-4o as the auxiliary LLM grader</strong>. For each question, the grader receives: question text, reference answer, and agent hypothesis; outputs a binary judgment under category-conditioned instructions (tolerance for off-by-one temporal counts, rubric-style scoring for preference items, abstention handling). Reports accuracy as fraction of questions where grader answers affirmatively.</p><hr><h2 id="_4-experiments" tabindex="-1">4. Experiments <a class="header-anchor" href="#_4-experiments" aria-label="Permalink to &quot;4. Experiments&quot;">​</a></h2><h3 id="_4-1-experiment-1-retrieval-mode-harness-and-tool-calling-method" tabindex="-1">4.1. Experiment 1: Retrieval Mode, Harness, and Tool Calling Method <a class="header-anchor" href="#_4-1-experiment-1-retrieval-mode-harness-and-tool-calling-method" aria-label="Permalink to &quot;4.1. Experiment 1: Retrieval Mode, Harness, and Tool Calling Method&quot;">​</a></h3><p><strong>Goal</strong>: Isolate how retrieval mode (grep-only vs. vector-only), agent harness (Chronos vs. Claude Code vs. Codex vs. Gemini CLI), and tool calling method (standard inline vs. programmatic file-based) jointly affect end-to-end accuracy when the full per-question haystack is exposed.</p><h4 id="_4-1-3-results" tabindex="-1">4.1.3. Results <a class="header-anchor" href="#_4-1-3-results" aria-label="Permalink to &quot;4.1.3. Results&quot;">​</a></h4><p><strong>Table 1</strong>: Overall accuracy (%) on 116-question LongMemEval-S subset.</p><table tabindex="0"><thead><tr><th>Model</th><th>Harness</th><th>grep (inline)</th><th>vector (inline)</th><th>grep (programmatic)</th><th>vector (programmatic)</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>Chronos</td><td><strong>93.1</strong></td><td>83.6</td><td>80.2</td><td>81.9</td></tr><tr><td>Claude Opus 4.6</td><td>Claude Code</td><td>76.7</td><td>75.0</td><td>68.1</td><td><strong>79.3</strong></td></tr><tr><td>Claude Haiku 4.5</td><td>Chronos</td><td><strong>83.6</strong></td><td>76.7</td><td><strong>83.6</strong></td><td>81.9</td></tr><tr><td>Claude Haiku 4.5</td><td>Claude Code</td><td><strong>55.2</strong></td><td>44.0</td><td><strong>37.1</strong></td><td>32.8</td></tr><tr><td>GPT-5.4</td><td>Chronos</td><td><strong>89.7</strong></td><td>81.9</td><td><strong>87.1</strong></td><td>75.0</td></tr><tr><td>GPT-5.4</td><td>Codex CLI</td><td><strong>93.1</strong></td><td>75.9</td><td>55.2</td><td><strong>67.2</strong></td></tr><tr><td>Gemini 3.1 Pro</td><td>Chronos</td><td><strong>91.4</strong></td><td>82.8</td><td><strong>79.3</strong></td><td>76.7</td></tr><tr><td>Gemini 3.1 Pro</td><td>Gemini CLI</td><td><strong>81.9</strong></td><td>75.0</td><td>81.0</td><td><strong>82.8</strong></td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td>Chronos</td><td><strong>86.2</strong></td><td>62.9</td><td><strong>85.3</strong></td><td>72.4</td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td>Gemini CLI</td><td><strong>87.1</strong></td><td>67.2</td><td>68.1</td><td><strong>74.1</strong></td></tr></tbody></table><p><strong>Key findings:</strong></p><ul><li>With <strong>inline delivery</strong>: lexical search (grep) uniformly stronger than dense retrieval for every harness–model pair <ul><li>Largest margin: Chronos + Gemini 3.1 Flash-Lite (86.2% vs. 62.9%)</li><li>Narrowest: Claude Code + Claude Opus 4.6 (76.7% vs. 75.0%)</li><li>On Chronos, inline grep spans 83.6–93.1%; inline vector spans 62.9–83.6%</li></ul></li><li><strong>Harness effect</strong>: Same Claude Opus 4.6 backbone reaches 93.1% under Chronos but only 76.7% under Claude Code — changing the harness shifts the ceiling by roughly as much as swapping retrievers within a fixed harness</li><li><strong>Programmatic delivery reshuffles</strong> the comparison: programmatic vector exceeds programmatic grep on 5 of 10 harness–model pairs <ul><li>Sharpest regression: Codex + GPT-5.4 falls from 93.1% (inline grep) to 55.2% (programmatic grep)</li></ul></li></ul><h4 id="_4-1-4-discussion" tabindex="-1">4.1.4. Discussion <a class="header-anchor" href="#_4-1-4-discussion" aria-label="Permalink to &quot;4.1.4. Discussion&quot;">​</a></h4><p><strong>LongMemEval rewards recovering literal witnesses</strong> (exact dates, counts, preferences, spans). Lexical tools surface those strings without an embedding bottleneck, explaining why inline grep is a strong default.</p><p><strong>&quot;Retrieval mode&quot; is not measured in isolation</strong>: The harness shapes the system prompt, tool descriptions, and how hits are rendered back into chat — all influence how the model schedules queries and decides when to stop. &quot;Retrieval&quot; in Table 1 is really <strong>retrieval-plus-orchestration</strong>.</p><p><strong>Programmatic delivery</strong> changes the task from &quot;read the tool message&quot; to &quot;locate, open, and integrate an artifact.&quot; When that second stage is brittle, accuracy collapses independently of retrieval quality. Agent papers should report both retrieval mechanics and the delivery path, because <strong>file-based routing is itself a tool-use stress test</strong>.</p><p><strong>Failure mode asymmetry:</strong></p><ul><li>Grep = deliberately narrow: rewards high-precision patterns, punishes vocabulary mismatch</li><li>Dense = deliberately broad: surfaces paraphrases but elevates semantically &quot;near&quot; distractors</li></ul><p><strong>Weaker models</strong> (Claude Haiku 4.5 on Claude Code) show especially large inline grep–vector gaps. Hypothesis: weaker models are less consistent at iterative query refinement and reranker-aware reading, hurting dense retrieval more than pattern-triggered lexical recovery when evidence is literally present. <strong>&quot;Default to vector&quot; recommendations should be conditioned on backbone strength</strong> and whether the task rewards literal span recovery vs. conceptual blending.</p><hr><h3 id="_4-2-experiment-2-context-scaling-with-increasing-noise" tabindex="-1">4.2. Experiment 2: Context Scaling with Increasing Noise <a class="header-anchor" href="#_4-2-experiment-2-context-scaling-with-increasing-noise" aria-label="Permalink to &quot;4.2. Experiment 2: Context Scaling with Increasing Noise&quot;">​</a></h3><p><strong>Goal</strong>: Examine how lexical and dense retrieval diverge as the model is exposed to more sessions from the same per-question bundle. Long-memory QA interleaves oracle sessions with distractors — as session limit increases, both retrievers see additional irrelevant material.</p><h4 id="_4-2-2-experimental-setup" tabindex="-1">4.2.2. Experimental Setup <a class="header-anchor" href="#_4-2-2-experimental-setup" aria-label="Permalink to &quot;4.2.2. Experimental Setup&quot;">​</a></h4><p>Vary the per-question session limit across: <strong>s5, s10, s20, s30, full</strong> (where full = complete haystack of 39–66 sessions per item). Oracle sessions always retained; remaining slots filled with distractors sampled from other sessions in the same bundle.</p><h4 id="_4-2-3-results" tabindex="-1">4.2.3. Results <a class="header-anchor" href="#_4-2-3-results" aria-label="Permalink to &quot;4.2.3. Results&quot;">​</a></h4><p><strong>Table 2</strong>: Experiment 2 (grep-only) — accuracy (%) by session-limit configuration.</p><table tabindex="0"><thead><tr><th>Model</th><th>Harness</th><th>s5</th><th>s10</th><th>s20</th><th>s30</th><th>full</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>Chronos</td><td>89.3</td><td>89.7</td><td>90.5</td><td>85.3</td><td>89.7</td></tr><tr><td>Claude Opus 4.6</td><td>Claude Code</td><td>91.4</td><td>94.0</td><td><strong>95.7</strong></td><td>90.5</td><td>94.0</td></tr><tr><td>Claude Haiku 4.5</td><td>Chronos</td><td>83.7</td><td>84.5</td><td><strong>86.2</strong></td><td>85.3</td><td>83.6</td></tr><tr><td>Claude Haiku 4.5</td><td>Claude Code</td><td><strong>89.7</strong></td><td>87.1</td><td>83.6</td><td>80.2</td><td>81.9</td></tr><tr><td>GPT-5.4</td><td>Chronos</td><td><strong>83.2</strong></td><td>82.8</td><td>81.9</td><td>78.5</td><td>78.5</td></tr><tr><td>Gemini 3.1 Pro</td><td>Chronos</td><td>86.2</td><td>86.6</td><td><strong>87.4</strong></td><td>82.2</td><td>86.6</td></tr><tr><td>Gemini 3.1 Pro</td><td>Gemini CLI</td><td>78.1</td><td>78.5</td><td><strong>79.2</strong></td><td>74.7</td><td>78.5</td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td>Chronos</td><td>88.8</td><td>89.2</td><td><strong>90.0</strong></td><td>84.8</td><td>89.2</td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td>Gemini CLI</td><td>70.4</td><td>70.7</td><td><strong>71.3</strong></td><td>67.2</td><td>70.7</td></tr></tbody></table><p><strong>Table 3</strong>: Experiment 2 (vector-only) — accuracy (%) by session-limit configuration.</p><table tabindex="0"><thead><tr><th>Model</th><th>Harness</th><th>s5</th><th>s10</th><th>s20</th><th>s30</th><th>full</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>Chronos</td><td>94.0</td><td><strong>94.8</strong></td><td>92.2</td><td>84.5</td><td>92.2</td></tr><tr><td>Claude Opus 4.6</td><td>Claude Code</td><td>77.6</td><td>72.4</td><td>75.0</td><td><strong>78.4</strong></td><td>72.4</td></tr><tr><td>Claude Haiku 4.5</td><td>Chronos</td><td>87.9</td><td><strong>89.7</strong></td><td><strong>90.5</strong></td><td>87.1</td><td>87.9</td></tr><tr><td>Claude Haiku 4.5</td><td>Claude Code</td><td>50.0</td><td>47.4</td><td>50.9</td><td>48.3</td><td>44.0</td></tr><tr><td>GPT-5.4</td><td>Chronos</td><td>88.8</td><td><strong>94.0</strong></td><td>86.2</td><td>82.8</td><td>82.8</td></tr><tr><td>Gemini 3.1 Pro</td><td>Chronos</td><td><strong>92.2</strong></td><td>91.4</td><td>87.1</td><td>85.3</td><td>84.5</td></tr><tr><td>Gemini 3.1 Pro</td><td>Gemini CLI</td><td>84.5</td><td>83.6</td><td>82.8</td><td>85.3</td><td><strong>89.7</strong></td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td>Chronos</td><td><strong>88.8</strong></td><td><strong>88.8</strong></td><td>87.9</td><td><strong>88.8</strong></td><td>83.6</td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td>Gemini CLI</td><td>69.8</td><td>69.8</td><td><strong>76.7</strong></td><td>70.7</td><td>74.1</td></tr></tbody></table><p><strong>Key findings:</strong></p><ul><li><strong>Grep accuracy is not monotone</strong>: Chronos Opus rises to 90.5% at s20, dips to 85.3% at s30, then reaches 89.7% at full</li><li>At s5, Chronos <strong>vector</strong> (87.9–94.0%) outperforms Chronos <strong>grep</strong> (83.2–89.7%) — vector is stronger at low session counts</li><li><strong>Retriever ordering depends on harness</strong>: Claude Code favors grep for Opus/Haiku at every configuration; Gemini CLI Pro favors vector throughout; Chronos shows crossings</li><li>Claude Code Opus peaks at s20 (95.7% grep) — highest single result in Table 2</li></ul><h4 id="_4-2-4-discussion" tabindex="-1">4.2.4. Discussion <a class="header-anchor" href="#_4-2-4-discussion" aria-label="Permalink to &quot;4.2.4. Discussion&quot;">​</a></h4><p>A common intuition holds that lexical search suffices on small corpora but breaks at scale. Our study <strong>partially supports this</strong> — vector retrieval often stronger at low session counts — but reveals the <strong>crossover depends on harness and backbone</strong>, not corpus size alone.</p><p><strong>Useful abstraction:</strong></p><ul><li>Dense retrieval explores <strong>neighborhoods in embedding space</strong>: recovers indirect mentions but admits topical false friends as sessions accumulate</li><li>Lexical retrieval exploits <strong>surface cues</strong>: brittle to phrasing, yet when the agent discovers a discriminative pattern it can be ruthlessly precise</li></ul><p><strong>Persistent stable preferences by harness:</strong></p><ul><li>Claude Code: favors grep for Opus/Haiku at every configuration</li><li>Gemini CLI Pro: favors vector throughout, gap widening to 89.7% vs. 78.5% at full</li></ul><p>These <strong>vendor-stable patterns imply stable inductive biases</strong> introduced by provider tooling: default hints, stdout chunking into transcript, tool error surfaces, and cultural defaults in how the CLI agent phrases searches. Migration between CLI stacks is <strong>not retrieval-interchangeable</strong> even when the on-disk corpus is byte-identical.</p><p><strong>Scaling curves should be read as samples from a stochastic outer loop</strong> (distractors are redrawn when session limit changes), not as smooth capacity laws. Mid-grid peaks need not indicate &quot;30 sessions is easier than 20&quot; in any absolute sense.</p><hr><h2 id="_5-limitations" tabindex="-1">5. Limitations <a class="header-anchor" href="#_5-limitations" aria-label="Permalink to &quot;5. Limitations&quot;">​</a></h2><p>Conclusions are tied to <strong>long-memory conversational QA</strong>: questions grounded in multi-session chat, explicit time expressions, and personal/user facts. In domains where evidence is rarely literal (scientific synthesis over paraphrased abstracts, visual-heavy documents, code semantics), dense retrieval and hybrid routing may look different. <strong>The paper does not claim that grep &quot;beats&quot; vector in general</strong> — only that it can win end-to-end under the task distribution and corpora studied.</p><hr><h2 id="_6-conclusion" tabindex="-1">6. Conclusion <a class="header-anchor" href="#_6-conclusion" aria-label="Permalink to &quot;6. Conclusion&quot;">​</a></h2><p>Key findings:</p><ol><li><strong>Inline grep exceeds inline vector for every harness-model pair</strong> evaluated on LongMemEval-S</li><li><strong>Overall scores depend strongly on harness and tool-calling style</strong> — file-based delivery and provider CLI shells can invert or erase the lexical advantage without any change to the corpus</li><li><strong>Harness-level accuracy shifts</strong> are comparable in magnitude to swapping retrievers within a fixed harness — &quot;retrieval&quot; is really retrieval-plus-orchestration</li></ol><p><strong>Implication</strong>: Retrieval mechanics, harness orchestration, and delivery path must be treated as a <strong>single jointly-evaluated system</strong> rather than independent design choices.</p><p><strong>Future work</strong>: hybrid retrieval policies, non-chat corpora, broader vendor coverage.</p><hr><h2 id="appendix-a-per-category-accuracy" tabindex="-1">Appendix A: Per-Category Accuracy <a class="header-anchor" href="#appendix-a-per-category-accuracy" aria-label="Permalink to &quot;Appendix A: Per-Category Accuracy&quot;">​</a></h2><p><strong>Table 4</strong>: Per-category accuracy (%) on 116-question subset for Chronos harness (grep-only, inline, full haystack). Grader: GPT-4o.</p><p>Categories: KU = knowledge-update, MS = multi-session, SS-A = single-session-assistant, SS-P = single-session-preference, SS-U = single-session-user, TR = temporal-reasoning.</p><table tabindex="0"><thead><tr><th>Model</th><th>KU</th><th>MS</th><th>SS-A</th><th>SS-P</th><th>SS-U</th><th>TR</th></tr></thead><tbody><tr><td>Claude Opus 4.6</td><td>94.4</td><td>83.9</td><td><strong>100.0</strong></td><td><strong>100.0</strong></td><td>87.5</td><td>87.1</td></tr><tr><td>Claude Haiku 4.5</td><td>83.3</td><td>71.0</td><td><strong>100.0</strong></td><td>85.7</td><td>87.5</td><td>87.1</td></tr><tr><td>GPT-5.4</td><td>77.8</td><td>74.2</td><td>92.3</td><td>85.7</td><td><strong>93.8</strong></td><td>67.7</td></tr><tr><td>Gemini 3.1 Pro</td><td>88.8</td><td>69.3</td><td><strong>100.0</strong></td><td>85.7</td><td>81.3</td><td><strong>100.0</strong></td></tr><tr><td>Gemini 3.1 Flash-Lite</td><td><strong>94.3</strong></td><td>72.6</td><td><strong>100.0</strong></td><td><strong>100.0</strong></td><td>81.3</td><td><strong>100.0</strong></td></tr></tbody></table><p>Notable: All models achieve 100% on SS-A (single-session-assistant) under Chronos + grep except GPT-5.4 (92.3%). Multi-session (MS) is the hardest category across all models.</p><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ul><li>Wu et al. (2025): LongMemEval benchmark</li><li>Sen et al. (2026): Chronos — temporal-aware conversational agents (arXiv:2603.16862)</li><li>Gao et al. (2024): RAG survey (arXiv:2312.10997)</li><li>Thakur et al. (2021): BEIR benchmark</li><li>Liu et al. (2024): Lost in the Middle — context rot in long contexts</li><li>Packer et al. (2023): MemGPT — file-based memory management</li><li>Yao et al. (2023): ReAct — reasoning + acting paradigm</li><li>Karpukhin et al. (2020): Dense Passage Retrieval (DPR)</li><li>Formal et al. (2021): SPLADE v2</li><li>Lumer et al. (2025a): Tool and agent selection survey</li><li>Gulati et al. (2026): RRF for spreadsheet understanding (arXiv:2601.08741)</li></ul>',123)])])}const p=t(n,[["render",o]]);export{u as __pageData,p as default};
